import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatTest {

    @Test
    void testGetEscapeCharacter_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        Character escapeChar = format.getEscapeCharacter();
        assertNull(escapeChar, "Default CSVFormat escapeCharacter should be null");
    }

    @Test
    void testGetEscapeCharacter_InformixUnload() {
        CSVFormat format = CSVFormat.INFORMIX_UNLOAD;
        Character escapeChar = format.getEscapeCharacter();
        assertNotNull(escapeChar, "INFORMIX_UNLOAD escapeCharacter should not be null");
        assertEquals('\\', escapeChar.charValue(), "INFORMIX_UNLOAD escapeCharacter should be backslash");
    }

    @Test
    void testGetEscapeCharacter_MySQL() {
        CSVFormat format = CSVFormat.MYSQL;
        Character escapeChar = format.getEscapeCharacter();
        assertNotNull(escapeChar, "MYSQL escapeCharacter should not be null");
        assertEquals('\\', escapeChar.charValue(), "MYSQL escapeCharacter should be backslash");
    }

    @Test
    void testGetEscapeCharacter_PostgreSQLCSV() {
        CSVFormat format = CSVFormat.POSTGRESQL_CSV;
        Character escapeChar = format.getEscapeCharacter();
        assertNotNull(escapeChar, "POSTGRESQL_CSV escapeCharacter should not be null");
        assertEquals('"', escapeChar.charValue(), "POSTGRESQL_CSV escapeCharacter should be double quote");
    }

    @Test
    void testGetEscapeCharacter_PostgreSQLText() {
        CSVFormat format = CSVFormat.POSTGRESQL_TEXT;
        Character escapeChar = format.getEscapeCharacter();
        assertNotNull(escapeChar, "POSTGRESQL_TEXT escapeCharacter should not be null");
        assertEquals('"', escapeChar.charValue(), "POSTGRESQL_TEXT escapeCharacter should be double quote");
    }

    @Test
    void testGetEscapeCharacter_WithEscapeMethod() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        CSVFormat withEscapeChar = baseFormat.withEscape('\\');
        Character escapeChar = withEscapeChar.getEscapeCharacter();
        assertNotNull(escapeChar, "Escape character should be set");
        assertEquals('\\', escapeChar.charValue(), "Escape character should be backslash");
    }

    @Test
    void testGetEscapeCharacter_WithEscapeMethod_Null() {
        CSVFormat baseFormat = CSVFormat.DEFAULT.withEscape((Character) null);
        Character escapeChar = baseFormat.getEscapeCharacter();
        assertNull(escapeChar, "Escape character should be null after setting null");
    }
}
